import sys
def solve():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        n=int(next(it)); x=int(next(it))
        found=False
        for _ in range(n):
            if int(next(it))==x:
                found=True
        out.append('YES' if found else 'NO')
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

